import{_ as t}from"./chunks/apfpv.djmBxdWp.js";import{c as a,Q as e,j as i,m as p}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"APFPV прошивка від OpenIPC","description":"Новий тип прошивки **APFPV** від команди **OpenIPC** призначений для експериментів у сфері прямої WiFi-комунікації між VTX та наземною станцією","frontmatter":{"title":"APFPV прошивка від OpenIPC","date":"2025-05-30T00:00:00.000Z","description":"Новий тип прошивки **APFPV** від команди **OpenIPC** призначений для експериментів у сфері прямої WiFi-комунікації між VTX та наземною станцією","tags":["APFPV firmware","apfpv firmaware OpenIPC","RTL8812AU","RTL8733BU"],"head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/updates/posts/2025-05-30-apfpv"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/updates/posts/2025-05-30-apfpv"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/updates/posts/2025-05-30-apfpv"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/updates/posts/2025-05-30-apfpv"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/updates/posts/2025-05-30-apfpv"}],["meta",{"property":"og:title","content":"APFPV прошивка від OpenIPC"}],["meta",{"property":"og:description","content":"Новий тип прошивки **APFPV** від команди **OpenIPC** призначений для експериментів у сфері прямої WiFi-комунікації між VTX та наземною станцією"}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-default.png"}],["meta",{"property":"og:locale","content":"uk_UA"}],["meta",{"property":"og:locale:alternate","content":"en_US"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-default.png"}],["meta",{"name":"twitter:title","content":"APFPV прошивка від OpenIPC"}],["meta",{"name":"twitter:description","content":"Новий тип прошивки **APFPV** від команди **OpenIPC** призначений для експериментів у сфері прямої WiFi-комунікації між VTX та наземною станцією"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Головна\\",\\"item\\":\\"https://openfpv.com.ua/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Оновлення\\",\\"item\\":\\"https://openfpv.com.ua/updates\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"APFPV прошивка від OpenIPC\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"APFPV прошивка від OpenIPC\\",\\"description\\":\\"Новий тип прошивки **APFPV** від команди **OpenIPC** призначений для експериментів у сфері прямої WiFi-комунікації між VTX та наземною станцією\\",\\"inLanguage\\":\\"uk-UA\\",\\"url\\":\\"https://openfpv.com.ua/updates/posts/2025-05-30-apfpv\\",\\"image\\":\\"https://openfpv.com.ua/og-default.png\\",\\"dateModified\\":\\"2026-05-31T08:38:19.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"updates/posts/2025-05-30-apfpv.md","filePath":"updates/posts/2025-05-30-apfpv.md","lastUpdated":1780216699000}'),n={name:"updates/posts/2025-05-30-apfpv.md"};function r(o,s,l,h,d,g){return e(),i("div",null,[...s[0]||(s[0]=[p('<h1 id="про-apfpv" tabindex="-1">Про APFPV <a class="header-anchor" href="#про-apfpv" aria-label="Permalink to &quot;Про APFPV&quot;">​</a></h1><p>Новий тип прошивки <strong>APFPV</strong> від команди <strong>OpenIPC</strong> призначений для експериментів у сфері прямої WiFi-комунікації між VTX та наземною станцією.</p><p>Ця прошивка не є панацеєю або великою інновацією, а насамперед орієнтована на новачків, яким складно розібратися з налаштуванням систем зв’язку <strong>WFB-NG</strong> та <strong>RubyFPV</strong>. Вона також буде корисною для тих, кому потрібен зв’язок з низькошвидкісними пристроями, такими як автомобілі, човни або навіть літаки та квадрокоптери (але без аеробатики). Затримка сигналу залежить від багатьох факторів і зазвичай становить від <strong>40 до 70 мс</strong>.</p><img src="'+t+`" alt="alink" width="150px"><p>Ще однією перевагою прошивки є <strong>відсутність вимог до WiFi-чіпа базової станції</strong> — це може бути будь-який пристрій. Таким чином, зовнішні пристрої від TP-Link, Ubiquiti та інші можуть виступати як базова станція, адже мають гарні вбудовані антени для надійного зв’язку.</p><p>Прошивка VTX включає два драйвери для популярних WiFi-чіпів — <strong>RTL8812AU</strong> та <strong>RTL8733BU</strong>, що забезпечує максимальну сумісність із різними пристроями.</p><hr><h1 id="встановлення-прошивки" tabindex="-1">Встановлення прошивки <a class="header-anchor" href="#встановлення-прошивки" aria-label="Permalink to &quot;Встановлення прошивки&quot;">​</a></h1><p>Завантажте архів із прошивкою та розпакуйте його:</p><p><a href="https://github.com/OpenIPC/builder/releases/download/latest/openipc.ssc338q-nor-apfpv.tgz" target="_blank" rel="noreferrer">https://github.com/OpenIPC/builder/releases/download/latest/openipc.ssc338q-nor-apfpv.tgz</a></p><p>Скопіюйте файли в <code>/tmp</code> за допомогою <strong>WinSCP</strong> (протокол SCP) або іншим способом і встановіть командою:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sysupgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -z</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --kernel=/tmp/uImage.ssc338q</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rootfs=/tmp/rootfs.squashfs.ssc338q</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Якщо ваш пристрій підключений до Інтернету, то встановлення ще простіше — однією командою:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sysupgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url=https://github.com/OpenIPC/builder/releases/download/latest/openipc.ssc338q-nor-apfpv.tgz</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Після встановлення прошивки перезавантажте пристрій. Потім підключіться до точки доступу <strong>&quot;OpenIPC&quot;</strong> з паролем <strong>&quot;12345678&quot;</strong>. Ваш пристрій отримає динамічну адресу з мережі <strong>192.168.0.0/24</strong>.</p><div class="warning custom-block"><p class="custom-block-title">Важливо</p><p>За замовчуванням <strong>Majestic</strong> передає відео UDP/RTP на адресу <strong>192.168.0.10</strong>, а WebUI прошивки доступна за адресою <strong>192.168.0.1</strong> і відкривається у будь-якому браузері.</p></div><hr><h1 id="перегляд-відео" tabindex="-1">Перегляд відео <a class="header-anchor" href="#перегляд-відео" aria-label="Permalink to &quot;Перегляд відео&quot;">​</a></h1><p>Щоб переглянути відео, можна:</p><ul><li>скористатися програмою <strong>PixelPilot</strong> на Android;</li><li>або на Linux-комп’ютері запустити стандартну команду <strong>gstreamer</strong>:</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gst-launch-1.0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> udpsrc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5600</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> !</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> application/x-rtp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> !</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rtph265depay</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> !</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> avdec_h265</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> !</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fpsdisplaysink</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Також можна використовувати будь-які інші програми, які підтримують прийом <strong>RTP-потоку через UDP</strong> на порту <strong>5600</strong>.</p><hr><h1 id="зміна-параметрів-wifi" tabindex="-1">Зміна параметрів WiFi <a class="header-anchor" href="#зміна-параметрів-wifi" aria-label="Permalink to &quot;Зміна параметрів WiFi&quot;">​</a></h1><p>Щоб змінити ім’я точки доступу та пароль на VTX, виконайте наступні команди через UART або SSH:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fw_setenv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wlanssid</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Drone</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fw_setenv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wlanpass</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openipcfpv</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div>`,26)])])}const F=a(n,[["render",r]]);export{u as __pageData,F as default};
